import{_ as i,c as a,o as t,ak as r}from"./chunks/framework.CYxz2ou1.js";const _=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoMind/C-工作/2-软实力/如何做好技术主R.md","filePath":"NanoMind/C-工作/2-软实力/如何做好技术主R.md","lastUpdated":1775467143000}'),o={name:"NanoMind/C-工作/2-软实力/如何做好技术主R.md"};function e(n,l,s,p,u,d){return t(),a("div",null,[...l[0]||(l[0]=[r('<h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>技术主 R(也叫研发主 R，Feature Owner)，&quot;R&quot; 通常是 &quot;Responsibility&quot;(责任)的缩写，即一个项目的技术负责人，是主导和协调整个需求开发流程的关键角色，是一个项目从需求方案评审到交付的全流程技术领导力主负责。</p><p>除了必备的技术能力之外，根据项目的性质规模不同还需要主 R 具备跨部门沟通，资源协调和项目管理能力，同时还需要足够的责任心。</p><h2 id="意义" tabindex="-1">意义 <a class="header-anchor" href="#意义" aria-label="Permalink to &quot;意义&quot;">​</a></h2><p>一个稍显规模的研发项目，在跨工种团队协作式完成的过程中，技术主 R 会对项目的技术方案实现，研发进度追踪，研发质量保证，研发成本控制起到关键作用，可以更加专业和高效的支撑项目的保质保量交付。</p><p>对于主 R，在这个过程中也可以深刻体会跨组合作，锻炼自己的沟通协调能力，对业务和技术方案也会有更深刻的理解。</p><h2 id="时机" tabindex="-1">时机 <a class="header-anchor" href="#时机" aria-label="Permalink to &quot;时机&quot;">​</a></h2><p>原则上每个研发项目都有技术主 R，一般简单的项目主要开发默认就是。稍显规模的项目，需求评审后一定要指定技术主 R，稍显规模主要指: 项目研发需要不同工种参与，交付周期预计 1 周以上。</p><h2 id="职责" tabindex="-1">职责 <a class="header-anchor" href="#职责" aria-label="Permalink to &quot;职责&quot;">​</a></h2><ul><li><strong>需求分析与对齐</strong>。负责整体需求分析以及产品，研发，测试的认知对齐，尤其是过程中遇到问题时候的重新对齐。</li><li><strong>方案设计</strong>。负责项目技术方案的设计与评审，制定项目排期，协调研发资源。</li><li><strong>进度追踪及风险管控</strong>。负责研发过程进行监控和管理，关键问题产研沟通，及时发现并解决研发中出现的问题。</li><li><strong>质量保证</strong>。协助团队成员解决技术难题，提高研发效率和代码质量。</li><li><strong>进展汇报</strong>。定期向团队和公司汇报项目研发进展，包括已完成的工作，未完成的工作和遇到的风险问题，项目延期要及时周知上下游。</li><li><strong>上线交付</strong>。负责项目上线交付。</li><li>核心模块研发(非必须)。负责项目关键核心模块研发，这个非必须，在中大型项目中，主 R 可以不参与具体模块研发。</li></ul><h2 id="如何做好" tabindex="-1">如何做好 <a class="header-anchor" href="#如何做好" aria-label="Permalink to &quot;如何做好&quot;">​</a></h2><p><strong>需求分析阶段</strong></p><ul><li>通读精读需求文档，确定需求边界，必要时和 pm 讨论细节。</li><li>确定需求的相关合作方，参与人。</li><li>讨论并分析项目规模，项目风险；确定关键节点。</li><li>讨论并确定需求的关键指标，设计思路。</li></ul><p><strong>方案设计阶段</strong></p><ul><li>形成技术方案</li><li>关键技术评审</li><li>组织技术方案评审</li><li>尤其是不同团队之间的接口，数据格式</li><li>确定技术方案</li><li>组织任务拆解，开发顺序，参与人任务和日程安排</li><li>维护群公告</li></ul><p><strong>方案实施阶段</strong></p><ul><li>跟进开发进程，处理过程风险</li><li>如有任务延期，跟进原因，报告风险，寻找解决方法</li><li>如有需求变更，跟进原因，进行方案修改，任务修改，公告新的计划，中间需要和 pm 深入沟通交流</li><li>相关资源是否到位</li><li>评估实现效果</li><li>组织代码 review</li><li>关键问题的发现和定位</li></ul><p><strong>需求验收阶段</strong></p><ul><li>提前了解测试方法，测试用例，测试过程</li><li>协调多方进行验收</li><li>跟进常见问题，协调资源</li><li>bug 太多</li><li>关键节点不同</li><li>资源不到位</li></ul><p><strong>上线交付阶段</strong></p><ul><li>上线申请文档，应有尽有</li><li>上线观测</li></ul><p><strong>需求完成</strong></p><ul><li>复盘需求研发过程中做得好的地方，做的不好的地方</li><li>质量怎么样</li><li>指标达成怎么样</li><li>研发效率如何</li><li>还有什么可以改进的</li></ul><h2 id="风险管理" tabindex="-1">风险管理 <a class="header-anchor" href="#风险管理" aria-label="Permalink to &quot;风险管理&quot;">​</a></h2><p>常见的风险：</p><ul><li>变更风险</li><li>资源风险</li><li>依赖风险</li><li>技术风险</li><li>进度风险</li><li>质量风险</li><li>安全风险</li></ul>',26)])])}const g=i(o,[["render",e]]);export{_ as __pageData,g as default};
